/**
 * Task #117 — Snapshot of the calibration token gate as observed by the
API server for THIS request. The dashboard polls this probe to render
a "Reviewer token: configured / missing / invalid" indicator before
the reviewer triggers a mutation that would otherwise 401.

 */
export interface CalibrationAuthStatus {
  /** True when `CALIBRATION_TOKEN` is set on the API process. When
false, every calibration mutation is open (single-reviewer / local
dev fallback) and the UI does not need to send a token.
 */
  serverRequiresToken: boolean;
  /** True when the request included a token via either the
`X-Calibration-Token` header or `Authorization: Bearer <token>`.
 */
  tokenPresented: boolean;
  /** True when a token was presented AND it matches the server's
configured token. Always false when the server has no token
configured (since there is nothing to compare against).
 */
  tokenValid: boolean;
  /** Derived: `!serverRequiresToken || tokenValid`. When false, the
UI should warn the reviewer that calibration mutations will be
rejected with 401.
 */
  mutationsAllowed: boolean;
}

