/**
 * Theme bucket used by the diagnostics panel to group matched phrases.
 */
export type HandwavyCategory =
  (typeof HandwavyCategory)[keyof typeof HandwavyCategory];

export const HandwavyCategory = {
  absence: "absence",
  hedging: "hedging",
  buzzword: "buzzword",
} as const;

export type HandwavyEditEntryCategory = {
  from: HandwavyCategory;
  to: HandwavyCategory;
};

/**
 * Before/after values for the rationale text. Empty string indicates the rationale was set or cleared.
 */
export type HandwavyEditEntryRationale = {
  from?: string;
  to?: string;
};

/**
 * Task #247 — before/after values for the phrase string itself,
present only when the reviewer renamed the marker via the
edit endpoint's `newPhrase` field. Both values are stored
already normalized (lowercase + collapsed whitespace).

 */
export type HandwavyEditEntryPhrase = {
  from: string;
  to: string;
};

/**
 * Single in-place edit applied to a curated hand-wavy marker phrase.
Records who made the change, when, and the before/after for whichever
fields actually changed (`category`, `rationale`, and/or — Task
#247 — the phrase string itself when a reviewer renamed it).
Fields that did not change are omitted to keep the audit log
compact.

 */
export interface HandwavyEditEntry {
  /** Reviewer name or email that performed the edit. Absent when no reviewer was supplied. */
  editedBy?: string;
  /** ISO 8601 timestamp of the edit. */
  editedAt: string;
  category?: HandwavyEditEntryCategory;
  /** Before/after values for the rationale text. Empty string indicates the rationale was set or cleared. */
  rationale?: HandwavyEditEntryRationale;
  /** Task #247 — before/after values for the phrase string itself,
present only when the reviewer renamed the marker via the
edit endpoint's `newPhrase` field. Both values are stored
already normalized (lowercase + collapsed whitespace).
 */
  phrase?: HandwavyEditEntryPhrase;
}

export interface HandwavyMarker {
  phrase: string;
  category: HandwavyCategory;
  /** Reviewer name or email that added the phrase. Absent for curated defaults. */
  addedBy?: string;
  /** ISO 8601 timestamp the phrase was added. Absent for curated defaults. */
  addedAt?: string;
  /** Free-text justification supplied by the reviewer at add time. */
  rationale?: string;
  /** Chronological log of in-place edits to this marker (most recent
last). Each entry records who changed what, when. Bounded
server-side per marker.
 */
  edits?: HandwavyEditEntry[];
}

/**
 * Task #135 — one element of a batch-removal history entry's `phrases`
array. Mirrors the audit metadata that a single-removal entry carries
at its top level. Per-phrase `reinstated*` fields track partial
reinstates so a reviewer can pull individual phrases back out of a
batch removal.

 */
export interface HandwavyBatchHistoryPhrase {
  phrase: string;
  category: HandwavyCategory;
  addedBy?: string;
  addedAt?: string;
  rationale?: string;
  /** Preserved on remove so reinstating still shows the edit history. */
  edits?: HandwavyEditEntry[];
  reinstated?: boolean;
  reinstatedBy?: string;
  reinstatedAt?: string;
}

/**
 * Removed-phrase audit record used so reviewers can reinstate a phrase
with original context. Single-removal entries populate `phrase` +
`category`; Task #135 batch-removal entries leave those empty and
instead populate `phrases` with the list of removed phrases.

 */
export interface HandwavyHistoryEntry {
  /** The removed phrase (single-removal entries). Empty/omitted on
Task #135 batch entries — see `phrases` instead.
 */
  phrase?: string;
  category?: HandwavyCategory;
  addedBy?: string;
  addedAt?: string;
  rationale?: string;
  /** Task */
  edits?: HandwavyEditEntry[];
  /** Reviewer name or email that removed the phrase(s). */
  removedBy?: string;
  /** ISO 8601 timestamp the phrase(s) were removed. */
  removedAt: string;
  /** Task #121 — true once a reviewer has reinstated this phrase
straight from the history log via POST
/feedback/calibration/handwavy-phrases/reinstate. The same row
cannot be reinstated twice — if the phrase is removed again, a
new history row is appended. For Task #135 batch entries this
is the AGGREGATE flag: true once every inner phrase has been
reinstated (see `phrases[].reinstated`).
 */
  reinstated?: boolean;
  /** Reviewer name or email that reinstated the phrase from this history entry. */
  reinstatedBy?: string;
  /** ISO 8601 timestamp the phrase was reinstated from this history entry. */
  reinstatedAt?: string;
  /** Task #130 — true when this history row was produced by a reviewer
undoing a brand-new add via POST
/feedback/calibration/handwavy-phrases/undo. The UI renders these
rows distinctly from manual removals so the audit trail clearly
reads "added then undone" rather than "added then removed".
 */
  undone?: boolean;
  /** Reviewer name or email that pressed Undo on this entry. */
  undoneBy?: string;
  /** Task #135 — present when the entry represents a batch removal.
Each item lists one removed phrase plus its original add-history
metadata and per-phrase reinstate state.
 */
  phrases?: HandwavyBatchHistoryPhrase[];
}

/**
 * Task #160 — Slim summary of one BATCH removal entry from the hand-wavy
phrase history log, scoped to the fields the reinstate-batch CLI
picker needs to show (timestamp, reviewer, phrase count,
already-reinstated flag, plus a small sample of removed phrases).

 */
export interface HandwavyPhraseRemovalBatchSummary {
  /** ISO 8601 timestamp of the batch removal entry. Pass back to /reinstate-batch as `removedAt`. */
  removedAt: string;
  /** Reviewer name or email recorded on the batch removal. Omitted if the original removal didn't supply one. */
  removedBy?: string;
  /** Number of phrases that were removed in this batch. */
  phraseCount: number;
  /** Aggregate flag — true once every inner phrase from this batch has already been reinstated. */
  reinstated: boolean;
  /**
   * First few removed phrases (capped at 5), shown in the picker so reviewers can identify the batch at a glance.
   * @maxItems 5
   */
  samplePhrases: string[];
}

/**
 * Task #160 — Response from GET
/feedback/calibration/handwavy-phrases/removal-batches. Newest batches
are returned first.

 */
export interface HandwavyPhraseRemovalBatchesList {
  /** Effective page size used for this response. */
  limit: number;
  /** Total number of batch removal entries in the history log (regardless of `limit`). */
  totalBatches: number;
  batches: HandwavyPhraseRemovalBatchSummary[];
}

/**
 * Task #176 — Detail response for one batch removal entry. Echoes the
FULL inner phrase list with per-phrase audit metadata so the
reinstate-batch CLI (and the Task #244 web reviewer picker) can
render every phrase the action would touch — not just the
5-phrase sample the list endpoint returns. `reinstatedCount`
/ `reinstated` together let callers spot a partial- or
already-fully-reinstated batch before re-firing the action.

 */
export interface HandwavyPhraseRemovalBatchDetail {
  /** ISO 8601 timestamp of the parent batch removal entry (echoes the path parameter). */
  removedAt: string;
  /** Reviewer name or email recorded on the batch removal. Omitted if the original removal didn't supply one. */
  removedBy?: string;
  /** Aggregate flag — true once every inner phrase from this batch has been reinstated. */
  reinstated: boolean;
  /** ISO 8601 timestamp the batch was fully reinstated, when `reinstated` is true. */
  reinstatedAt?: string;
  /** Reviewer name or email recorded on the batch-level reinstate, when `reinstated` is true. */
  reinstatedBy?: string;
  /** Total number of phrases in this batch. */
  phraseCount: number;
  /** Number of inner phrases that have already been reinstated (per-phrase or via a prior batch reinstate). */
  reinstatedCount: number;
  /** Full inner phrase list with per-phrase audit metadata. */
  phrases: HandwavyBatchHistoryPhrase[];
}

export type HandwavyPhraseRemovalBatchDetailErrorReason =
  (typeof HandwavyPhraseRemovalBatchDetailErrorReason)[keyof typeof HandwavyPhraseRemovalBatchDetailErrorReason];

export const HandwavyPhraseRemovalBatchDetailErrorReason = {
  "history-not-found": "history-not-found",
  "not-a-batch": "not-a-batch",
} as const;

/**
 * Task #176 — 404 response shape for the batch detail endpoint.
`reason` discriminates between "no matching removal-history entry"
and "matched a single-phrase removal" so callers can format a
targeted hint (e.g. the CLI suggests /reinstate for the latter).

 */
export interface HandwavyPhraseRemovalBatchDetailError {
  error: string;
  reason: HandwavyPhraseRemovalBatchDetailErrorReason;
}

export interface HandwavyPhrasesList {
  phrases: HandwavyMarker[];
  total: number;
  /** Removal audit log (most recent last). Bounded server-side. */
  history: HandwavyHistoryEntry[];
}

/**
 * Request body for the in-place edit endpoint. The `phrase` string
identifies which curated marker to update; provide at least one of
`category`, `rationale`, or `newPhrase` to actually change
something. Send an empty `rationale` string to clear an existing
rationale. Task #247 — `newPhrase` is the rename target; the edit
only changes the row identity when its normalized form differs
from the existing phrase, otherwise it is treated as a no-op.

 */
export interface HandwavyPhraseEditBody {
  /** Existing curated phrase to edit (matched after lowercase + whitespace normalization). */
  phrase: string;
  category?: HandwavyCategory;
  /** New rationale text. Empty string clears the existing rationale. */
  rationale?: string;
  /** Task #247 — Rename target. Normalized to lowercase + collapsed
whitespace before matching, and rejected when the normalized
form already belongs to another active marker. When the
normalized form matches the existing `phrase`, the rename is a
no-op; the request can still apply concurrent
`category`/`rationale` updates.
 */
  newPhrase?: string;
  /** Reviewer name or email recorded in the edit audit entry. Optional. */
  reviewer?: string;
}

export interface HandwavyPhraseBody {
  /** Marker phrase (case-insensitive substring match against report text after whitespace collapsing). */
  phrase: string;
  category?: HandwavyCategory;
  /** Task #114 — when true on POST, the server does NOT persist the phrase. It runs the
candidate phrase against the curated benchmark corpus (T1 LEGIT / T2 BORDERLINE
/ T3 SLOP / T4 HALLUCINATED fixtures) and returns a `dryRunMatches` block so
reviewers can see how many GREEN / YELLOW reports the phrase would have hit
before they confirm the add.

Task #155 — when true on DELETE for a single phrase, the server does NOT
mutate the active list, history, or cache and instead returns a
`HandwavyPhraseSingleRemoveDryRunResponse` (the same corpus + production
removal-impact summary as the batch dry-run, with `batch: false`).

Defaults to false (write-through behavior).
 */
  dryRun?: boolean;
  /** Reviewer name or email recorded in the audit trail. Optional. */
  reviewer?: string;
  /** Free-text justification recorded with the phrase. Only consulted on POST. */
  rationale?: string;
  /**
   * Task #125 — optional override for the upper bound on the production-archive
scan that backs the dry-run preview. Only consulted on the dry-run path
(the only place the production scan runs). Heavy-user installs can widen
the window for a stronger false-positive signal; small installs can tighten
it to focus on recent reporter behavior. Defaults to 2000 when omitted so
existing reviewers see no behavior change. The chosen value is echoed back
in `dryRunMatchesProductionLimit` so the UI can label the second signal
accurately.

Task #230 — also accepted on the DELETE single-phrase dry-run path
via `HandwavyPhraseBody`, which shares this body schema, so the
same reviewer-chosen window drives the single-phrase removal preview
too. The chosen value is echoed back in
`HandwavyPhraseSingleRemoveDryRunResponse.dryRunImpact.productionLimit`.

   * @minimum 100
   * @maximum 10000
   */
  productionScanLimit?: number;
}

